const ICONS = {
  "tune-up": "",
  "brakes": "",
  "drivetrain": "",
  "wheels": "",
  "suspension": "",
  "build": "",
  "general": ""
};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const name = url.pathname.replace(/^\/icons\//, '').replace(/\.png$/, '');

    if (!ICONS[name]) {
      return new Response('Not found', { status: 404 });
    }

    const bytes = Uint8Array.from(atob(ICONS[name]), c => c.charCodeAt(0));
    return new Response(bytes, {
      headers: {
        'Content-Type': 'image/png',
        'Cache-Control': 'public, max-age=86400',
        'Access-Control-Allow-Origin': '*',
      },
    });
  },
};
